import{_ as i,o as t,c as a,ak as n}from"./chunks/framework.BsiU-GuW.js";const u=JSON.parse('{"title":"5.6 Code Labs / Practice Appendix","description":"The dedicated appendix for Chapter 5 runnable scripts, environment requirements, demo entry points, and where to find full outputs.","frontmatter":{"title":"5.6 Code Labs / Practice Appendix","description":"The dedicated appendix for Chapter 5 runnable scripts, environment requirements, demo entry points, and where to find full outputs."},"headers":[],"relativePath":"en/guide/ch05/06-code-labs.md","filePath":"en/guide/ch05/06-code-labs.md"}'),s={name:"en/guide/ch05/06-code-labs.md"};function o(d,e,r,l,c,p){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="_5-6-code-labs-practice-appendix" tabindex="-1">5.6 Code Labs / Practice Appendix <a class="header-anchor" href="#_5-6-code-labs-practice-appendix" aria-label="Permalink to “5.6 Code Labs / Practice Appendix”">​</a></h1><p>This page is the <strong>practice appendix</strong> for Chapter 5. Its job is different from the four mainline pages:</p><ul><li><strong>mainline pages (5.1–5.4)</strong> explain concepts and decision logic;</li><li><strong>this appendix</strong> collects runnable entry points, dependencies, outputs, and implementation pointers;</li><li><strong>5.5</strong> remains optional frontier reading.</li></ul><h2 id="where-is-the-full-implementation" tabindex="-1">Where is the full implementation? <a class="header-anchor" href="#where-is-the-full-implementation" aria-label="Permalink to “Where is the full implementation?”">​</a></h2><p>All complete scripts, training logic, demos, and generated outputs are under <code>src/ch05/</code>.</p><h3 id="script-groups-by-topic" tabindex="-1">Script groups by topic <a class="header-anchor" href="#script-groups-by-topic" aria-label="Permalink to “Script groups by topic”">​</a></h3><table tabindex="0"><thead><tr><th>Mainline question</th><th>Local code area</th><th>Representative scripts</th></tr></thead><tbody><tr><td>How should data be prepared?</td><td>preprocessing</td><td><code>clip_hu_values/</code>, <code>medical_image_resampling/</code>, <code>n4itk_bias_correction/</code>, <code>white_stripe_normalization/</code>, <code>detect_metal_artifacts/</code>, <code>visualize_bias_field/</code></td></tr><tr><td>Why does segmentation work?</td><td>segmentation</td><td><code>lung_segmentation_network/</code>, <code>medical_segmentation_augmentation/</code></td></tr><tr><td>How should we think about classification and detection?</td><td>classification</td><td><code>medical_image_classification/</code></td></tr><tr><td>When should enhancement or restoration be used?</td><td>augmentation / restoration</td><td><code>medical_image_augmentation/</code>, <code>clahe_enhancement/</code>, plus the MRI bias-field tools</td></tr></tbody></table><hr><h2 id="recommended-reading-order-inside-src-ch05" tabindex="-1">Recommended reading order inside <code>src/ch05/</code> <a class="header-anchor" href="#recommended-reading-order-inside-src-ch05" aria-label="Permalink to “Recommended reading order inside src/ch05/”">​</a></h2><ol><li>Start with <code>src/ch05/README_EN.md</code> for the chapter-wide experiment index.</li><li>Then open the subfolder README for the script you want to run.</li><li>Use the local <code>output/</code> directory in each experiment to inspect generated images and reports.</li></ol><hr><h2 id="typical-run-pattern" tabindex="-1">Typical run pattern <a class="header-anchor" href="#typical-run-pattern" aria-label="Permalink to “Typical run pattern”">​</a></h2><p>Most Chapter 5 demos follow the same structure:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/ch05/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">experiment_nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Some experiments also provide a simplified entry or an extra test file:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> simple_augmentation.py</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test.py</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="environment-and-dependencies" tabindex="-1">Environment and dependencies <a class="header-anchor" href="#environment-and-dependencies" aria-label="Permalink to “Environment and dependencies”">​</a></h2><p>For Chapter 5 practice, dependencies are documented in:</p><ul><li><code>src/ch05/requirements.txt</code></li><li><code>src/ch05/README_EN.md</code></li><li>individual experiment READMEs when extra packages are needed</li></ul><p>Typical packages include:</p><ul><li><code>numpy</code>, <code>matplotlib</code>, <code>scipy</code>, <code>scikit-image</code></li><li><code>opencv-python</code></li><li><code>torch</code>, <code>torchvision</code></li><li><code>pydicom</code>, <code>nibabel</code>, <code>SimpleITK</code></li></ul><hr><h2 id="where-are-full-outputs-stored" tabindex="-1">Where are full outputs stored? <a class="header-anchor" href="#where-are-full-outputs-stored" aria-label="Permalink to “Where are full outputs stored?”">​</a></h2><p>Each experiment keeps its own generated artifacts, usually in one of these folders:</p><ul><li><code>output/</code></li><li><code>outputs/</code></li></ul><p>Examples:</p><ul><li><code>src/ch05/lung_segmentation_network/output/</code></li><li><code>src/ch05/medical_image_classification/output/</code></li><li><code>src/ch05/medical_image_augmentation/output/</code></li><li><code>src/ch05/clahe_enhancement/output/</code></li></ul><p>These folders hold figures, reports, and demo visualizations that would be too heavy for the main tutorial pages.</p><hr><h2 id="how-should-the-appendix-be-used" tabindex="-1">How should the appendix be used? <a class="header-anchor" href="#how-should-the-appendix-be-used" aria-label="Permalink to “How should the appendix be used?”">​</a></h2><p>Use this appendix when you want to:</p><ul><li>run the chapter code locally;</li><li>inspect full implementation details;</li><li>compare generated outputs;</li><li>understand environment setup and script entry points.</li></ul><p>Return to the mainline pages when you want to answer the conceptual questions of Chapter 5.</p><div class="tip custom-block"><p class="custom-block-title">One-sentence summary</p><p>The mainline pages explain <strong>why</strong>; this appendix and <code>src/ch05/</code> show <strong>how to run and inspect the full workflow</strong>.</p></div>`,35)])])}const m=i(s,[["render",o]]);export{u as __pageData,m as default};
